import React, { useEffect, useState } from "react";
import api from "../services/api";
import MovieRow from "../components/MovieRow";
import FeaturedMovie from "../components/FeaturedMovie";
import Header from "../components/Header";

export default () => {

  const [movieList, setMovieList] = useState([]);
  const [featuredData, setFeaturedData] = useState(null);
  const [blackHeader, setBlackHeader] = useState(false);

  useEffect(() => {
    const loadAll = async () => {
      try {
        const list = await api.getHomeList();

        console.log("BACKEND DATA:", list);

        setMovieList(list || []);

        // pega TODOS os filmes (não só originals)
        const allMovies = list?.flatMap(i => i.items?.results || []) || [];

        if (allMovies.length > 0) {
          const randomIndex = Math.floor(Math.random() * allMovies.length);
          const chosen = allMovies[randomIndex];

          const chosenInfo = await api.getMovieInfo(chosen.id);

          setFeaturedData(chosenInfo || chosen);
        }

      } catch (err) {
        console.log("ERRO AO CARREGAR HOME:", err);
      }
    };

    loadAll();
  }, []);

  useEffect(() => {
    const scrollListener = () => {
      setBlackHeader(window.scrollY > 10);
    };

    window.addEventListener("scroll", scrollListener);

    return () => {
      window.removeEventListener("scroll", scrollListener);
    };
  }, []);

  return (
    <div className="page">

      <Header black={blackHeader} />

      {/* FEATURED */}
      {featuredData && (
        <FeaturedMovie item={featuredData} />
      )}

      {/* LISTAS */}
      <section className="lists">
        {movieList?.length > 0 && movieList.map((item, key) => (
          <MovieRow
            key={key}
            title={item.title}
            items={item.items || { results: [] }}
          />
        ))}
      </section>

      {/* FOOTER */}
      <footer>
        Feito com ❤ pelo Lenine<br />
        Direitos de imagem para Netflix<br />
        Dados pegos do TheMovieDB
      </footer>

      {/* LOADING */}
      {movieList.length === 0 && (
        <div className="loading">
          <img
            src="https://media.wired.com/photos/592744d3f3e2356fd800bf00/3:2/w_2560%2Cc_limit/Netflix_LoadTime.gif"
            alt="Carregando"
          />
        </div>
      )}

    </div>
  );
};
